{"path":"/app/extract.js","content":"const fs = require('fs');

const buf = fs.readFileSync(process.argv[2]);

// Parse ELF64 header
const e_phoff = Number(buf.readBigUInt64LE(32));
const e_phentsize = buf.readUInt16LE(54);
const e_phnum = buf.readUInt16LE(56);

const result = {};

for (let i = 0; i < e_phnum; i++) {
  const off = e_phoff + i * e_phentsize;
  const type = buf.readUInt32LE(off);

  if (type === 1) { // PT_LOAD
    const offset = Number(buf.readBigUInt64LE(off + 8));
    const vaddr = Number(buf.readBigUInt64LE(off + 16));
    const filesz = Number(buf.readBigUInt64LE(off + 32));
    const memsz = Number(buf.readBigUInt64LE(off + 40));

    // Read all 4-byte aligned addresses from the file data
    for (let j = 0; j < filesz; j += 4) {
      const addr = vaddr + j;
      const val = buf.readUInt32LE(offset + j);
      result[addr] = val;
    }

    // For segments where memsz > filesz, the extra bytes are zero-filled (BSS-like)
    for (let j = filesz; j < memsz; j += 4) {
      const addr = vaddr + j;
      result[addr] = 0;
    }
  }
}

console.log(JSON.stringify(result));
"}

